import{_ as e,o as l,c as i,a4 as r}from"./chunks/framework.BhEBm8_q.js";const _=JSON.parse('{"title":"홈과 책장 보기","description":"","frontmatter":{},"headers":[],"relativePath":"03-home-library.md","filePath":"03-home-library.md"}'),o={name:"03-home-library.md"};function t(d,a,c,h,n,p){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="홈과-책장-보기" tabindex="-1">홈과 책장 보기 <a class="header-anchor" href="#홈과-책장-보기" aria-label="Permalink to “홈과 책장 보기”">​</a></h1><p><em>책장 보기·정렬 메뉴</em></p><p>홈은 <code>독서중</code> 영역과 책장 목록으로 구성됩니다. 위쪽 탭으로 책장을 바꾸고, 아래쪽 메뉴로 보기 방식을 조절합니다.</p><h2 id="독서중" tabindex="-1">독서중 <a class="header-anchor" href="#독서중" aria-label="Permalink to “독서중”">​</a></h2><p>최근에 실제로 읽은 문서를 빠르게 이어 열기 위한 공간입니다. 읽고 있는 책이 없으면 비어 있는 안내가 표시됩니다. 여기에 보이는 순서는 &quot;읽은 활동&quot; 기준이라, 새로 읽을수록 위로 올라옵니다.</p><h2 id="책장-종류" tabindex="-1">책장 종류 <a class="header-anchor" href="#책장-종류" aria-label="Permalink to “책장 종류”">​</a></h2><ul><li><code>Ebook 책장</code>: 직접 추가한 문서. 추가한 순서를 유지합니다.</li><li><code>매직 책장</code>: 선택한 폴더 스캔으로 찾은 문서.</li><li>수동 책장과 포토함으로 문서를 직접 분류할 수도 있습니다.</li></ul><h2 id="보기와-정렬-메뉴" tabindex="-1">보기와 정렬 메뉴 <a class="header-anchor" href="#보기와-정렬-메뉴" aria-label="Permalink to “보기와 정렬 메뉴”">​</a></h2><p>각 책장의 <code>{...}</code> 메뉴에서 다음을 바꿀 수 있습니다.</p><ul><li>보기: 격자 / 목록</li><li>정렬: 최근순 / 제목순 / 확장자순 / 수동순</li><li>선택 모드: 여러 문서를 한 번에 관리</li></ul><p>모든 책장은 타입과 문서 수에 관계없이 같은 메뉴 구성을 제공하므로, 한 곳에서 익히면 다른 책장에서도 그대로 쓸 수 있습니다.</p><h2 id="표지에서-보이는-정보" tabindex="-1">표지에서 보이는 정보 <a class="header-anchor" href="#표지에서-보이는-정보" aria-label="Permalink to “표지에서 보이는 정보”">​</a></h2><p>격자 표지에는 썸네일, 파일 타입, 제목, 진행률 바가 표시됩니다. 진행률로 어디까지 읽었는지 한눈에 알 수 있고, 다 읽은 문서는 색과 짧은 상태로 구분됩니다.</p><p>확장자순으로 정렬하면 같은 포맷끼리 묶여, PDF·EPUB·만화 등을 그룹으로 훑어보기 좋습니다.</p><h2 id="문서별-메뉴" tabindex="-1">문서별 메뉴 <a class="header-anchor" href="#문서별-메뉴" aria-label="Permalink to “문서별 메뉴”">​</a></h2><p>표지의 보조 메뉴에서 문서 단위 작업을 할 수 있습니다.</p><ul><li>문서 정보 보기</li><li>읽음 / 안 읽음 표시</li><li>텍스트 추출</li><li>책장에서 제거</li><li>삭제(확인 후 진행, 되돌릴 수 없는 작업은 빨간색으로 구분)</li></ul><blockquote><p>가이드 책장의 문서는 삭제·선택 삭제가 막혀 있습니다. 앱이 관리하는 문서이기 때문입니다.</p></blockquote>',18)])])}const m=e(o,[["render",t]]);export{_ as __pageData,m as default};
